// Filtre les acheteurs qui ont des critères définis
const items = $input.all();
const validBuyers = [];

for (const item of items) {
  const buyer = item.json;

  // Vérifier que l'acheteur a au moins un budget_max défini
  if (buyer.criteres_recherche && buyer.criteres_recherche.budget_max) {
    validBuyers.push({ json: buyer });
  } else {
    console.log(`Buyer ${buyer.id} skipped - no search criteria`);
  }
}

console.log(`Found ${validBuyers.length} valid buyers with criteria`);

if (validBuyers.length === 0) {
  return [{ json: { skip: true, message: 'Aucun acheteur avec critères définis' } }];
}

return validBuyers;

// Regroupe tous les biens en un seul array pour le passer à l'Edge Function
const allBiens = $input.all();
const biensList = allBiens.map(item => item.json);

console.log(`Prepared ${biensList.length} biens for matching`);

return [{ json: { biens: biensList } }];

// Merge buyer data with biens array
const buyerItems = $input.first();
const biensItems = $input.last();

const buyer = buyerItems.json;
const biens = biensItems.json.biens;

console.log(`Merging buyer ${buyer.id} with ${biens.length} biens`);

return [{
  json: {
    buyer_id: buyer.id,
    buyer_email: buyer.email,
    buyer_name: `${buyer.prenom} ${buyer.nom}`,
    buyer_criteria: buyer.criteres_recherche,
    properties: biens
  }
}];

// Prépare l'email avec les meilleurs matchs pour l'acheteur
const item = $input.first();
const matchings = item.json.matchings || [];
const buyerName = item.json.buyer_name || 'Cher client';
const buyerEmail = item.json.buyer_email;

// Trier par score décroissant
const sortedMatchings = matchings.sort((a, b) => b.score - a.score);

// Prendre top 5
const topMatchings = sortedMatchings.slice(0, 5);

// Générer le HTML des biens
const biensHTML = topMatchings.map((m, idx) => {
  const bien = item.json.properties.find(p => p.id === m.bien_id);

  return `
    <div style="border: 1px solid #ddd; padding: 15px; margin: 10px 0; border-radius: 8px;">
      <h3 style="margin-top: 0;">#${idx + 1} - ${bien.titre} (Score: ${m.score}/100)</h3>
      <p><strong>Prix :</strong> ${bien.prix.toLocaleString('fr-FR')}€ | <strong>Surface :</strong> ${bien.surface}m² | <strong>Pièces :</strong> ${bien.nb_pieces}</p>
      <p><strong>Ville :</strong> ${bien.ville}</p>

      <p><strong>✅ Points forts :</strong></p>
      <ul>
        ${m.points_forts.map(pf => `<li>${pf}</li>`).join('')}
      </ul>

      ${m.points_attention && m.points_attention.length > 0 ? `
        <p><strong>⚠️ Points d'attention :</strong></p>
        <ul>
          ${m.points_attention.map(pa => `<li>${pa}</li>`).join('')}
        </ul>
      ` : ''}

      <p style="background: #f0f8ff; padding: 10px; border-radius: 5px;">
        <strong>Recommandation :</strong> ${m.recommandation}
      </p>

      <p><a href="https://www.leboncoin.fr/ad/${bien.lbc_id}" style="background: #ff6b35; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px; display: inline-block;">Voir l'annonce</a></p>
    </div>
  `;
}).join('');

return [{
  json: {
    buyer_name: buyerName,
    buyer_email: buyerEmail,
    nb_matches: topMatchings.length,
    biens_html: biensHTML
  }
}];

// Calcule les stats globales de tous les matchings
const allItems = $input.all();

let totalBuyers = 0;
let totalMatchings = 0;
let totalEmailsSent = 0;
let buyersWithMatches = 0;

for (const item of allItems) {
  totalBuyers++;

  if (item.json.high_score_matches > 0) {
    buyersWithMatches++;
    totalMatchings += item.json.high_score_matches;
    totalEmailsSent++;
  }
}

const stats = {
  date: new Date().toISOString().split('T')[0],
  total_acheteurs_actifs: totalBuyers,
  acheteurs_avec_matchs: buyersWithMatches,
  total_matchings_generes: totalMatchings,
  emails_envoyes: totalEmailsSent,
  taux_matching: buyersWithMatches > 0 ? Math.round((buyersWithMatches / totalBuyers) * 100) : 0
};

console.log('Stats matching quotidien:', stats);

return [{ json: stats }];
